import json, sys, re

with open('ios_crash.ips') as f:
    lines = f.readlines()

metadata = json.loads(lines[0])
print("=== METADATA ===")
for k in ['app_name', 'bundleID', 'os_version', 'slice_uuid', 'build_version', 'name']:
    if k in metadata:
        print(f"  {k}: {metadata[k]}")

# Handle potential duplicate keys by renaming lowercase vmregioninfo
raw_body = ''.join(lines[1:])
raw_body = re.sub(r'"vmregioninfo"', '"vmregioninfo_lower"', raw_body)
crash = json.loads(raw_body)

print("\n=== EXCEPTION ===")
if 'exception' in crash:
    exc = crash['exception']
    for k in ['type', 'signal', 'subtype', 'codes']:
        if k in exc:
            print(f"  {k}: {exc[k]}")

print("\n=== ASI (Application Specific Information) ===")
if 'asi' in crash:
    for key, val in crash['asi'].items():
        for line in val:
            print(f"  [{key}] {line[:500]}")
else:
    print("  (not present)")

print(f"\n=== FAULTING THREAD: {crash.get('faultingThread', 'unknown')} ===")

# Show termination info
if 'termination' in crash:
    t = crash['termination']
    print(f"\n=== TERMINATION ===")
    for k in ['indicator', 'code', 'namespace', 'reasons']:
        if k in t:
            print(f"  {k}: {t[k]}")

